function a(t){if(!t)return"-";const e=new Date(t);return Number.isNaN(e.getTime())?t:e.toLocaleDateString("zh-CN")}function i(t){if(!t)return"-";const e=new Date(t);return Number.isNaN(e.getTime())?t:e.toLocaleString("zh-CN",{hour12:!1})}function u(t){return`¥${(t||0).toFixed(2)}`}function f(t){if(!t)return null;const e=new Date(t);if(Number.isNaN(e.getTime()))return null;const n=new Date;let r=n.getFullYear()-e.getFullYear();const o=n.getMonth()-e.getMonth();return(o<0||o===0&&n.getDate()<e.getDate())&&r--,r}export{i as a,u as b,f as c,a as f};
